previewCss:
.darma-loader-cssloaders-github-40 {
  display: inline-block;
  width: 80px;
  height: 10px;
  border-radius: 999px;
  background: color-mix(in srgb, var(--loader-color, #f97316) 16%, transparent);
  overflow: hidden;
}
.darma-loader-cssloaders-github-40::before {
      content: "";
      display: block;
      width: 42%;
      height: 100%;
      border-radius: inherit;
      background: linear-gradient(90deg, var(--loader-color, #f97316), var(--loader-secondary-color, #fed7aa));
      animation: darma-loader-cssloaders-github-40-progressSlide 0.9s ease-in-out infinite;
    }
    @keyframes darma-loader-cssloaders-github-40-progressSlide { 0% { transform: translateX(-120%); } 100% { transform: translateX(260%); } }

